{% if divisions %}Divisions (with positions and responsibility atoms — the school's complete organizational roster; name actors only from this list):
{% for d in divisions %}- {{ d.label }}{% if d.scope_summary %} — {{ d.scope_summary }}{% endif %}
{% if d.responsibilities %}  Division responsibilities:
{% for r in d.responsibilities %}    - {{ r.statement }}
{% endfor %}{% endif %}{% if d.positions %}  Positions:
{% for p in d.positions %}    - {{ p.label }} ({{ p.kind }}){% if p.scope_summary %} — {{ p.scope_summary }}{% endif %}
{% if p.responsibilities %}{% for r in p.responsibilities %}      - {{ r.statement }}
{% endfor %}{% endif %}{% endfor %}{% endif %}
{% endfor %}{% endif %}
